1415   /// @returns true if the predicate is EQ or NE.
1416   /// Determine if this is an equality predicate.
1417   static bool isEquality(Predicate Pred) {
1418     return Pred == FCMP_OEQ || Pred == FCMP_ONE || Pred == FCMP_UEQ ||
1419            Pred == FCMP_UNE;
1420   }
